Bash(node -e "
  const { z } = require\('zod'\);
  const { createCampaignSchema } = require\('./src/validators/schemas/campaignSchema'\);

  // valid payload
  const ok = createCampaignSchema.safeParse\({ name: 'Test', platform: 'meta' }\);
  console.assert\(ok.success, 'valid payload failed'\);
  console.assert\(ok.data.objective === 'conversions', 'default not applied'\);

  // unknown field stripped
  const stripped = createCampaignSchema.safeParse\({ name: 'T', platform: 'meta', teamId: 'INJECTED' }\);
  console.assert\(!stripped.success, 'strict\(\) did not reject unknown field'\);

  // invalid platform
  const bad = createCampaignSchema.safeParse\({ name: 'T', platform: 'tiktok' }\);
  console.assert\(!bad.success, 'invalid platform passed'\);

  console.log\('Schema validation tests passed'\);
")

